import { fetchOwnershipData } from "./provider.js";

const RENOUNCED_ADDRESSES = new Set([
  "0x0000000000000000000000000000000000000000",
  "0x000000000000000000000000000000000000dead"
]);

export async function analyzeOwnership({ chain, address }) {
  console.log("[analysis] ownership start", { chain, address });
  const data = await fetchOwnershipData(chain, address);

  let status = "UNKNOWN";
  const notes = [];
  const owner = String(data?.owner || "").toLowerCase();

  if (data?.verifiable && owner && RENOUNCED_ADDRESSES.has(owner)) {
    status = "PASS";
  } else if (data?.verifiable && owner) {
    status = "FAIL";
    notes.push(`Owner appears to be ${owner}.`);
  } else {
    status = "UNKNOWN";
    notes.push(data?.note || "Ownership could not be verified.");
  }

  console.log("[analysis] ownership success", { chain, address, status });
  return {
    status,
    owner: owner || "unknown",
    notes
  };
}

provider.js.content:
import { cfg } from "../lib/config.js";
import { fetchJson } from "../lib/http.js";

const CHAIN_CONFIG = {
  evm: {
    chain: "evm",
    rpcUrl: cfg.EVM_RPC_URL || cfg.ETH_RPC_URL || cfg.BSC_RPC_URL || cfg.BASE_RPC_URL || cfg.ARB_RPC_URL || cfg.POLYGON_RPC_URL || ""
  }
};

function safeErr(err) {
  return err?.response?.data?.error?.message || err?.response?.data?.message || err?.message || String(err);
}

export function inferChain(address, chainHint = "") {
  if (!address?.startsWith("0x")) {
    return { supported: false, chain: "unknown", reason: "unsupported_address_format" };
  }

  const requested = String(chainHint || "evm").toLowerCase();
  if (!cfg.SUPPORTED_CHAINS.includes(requested)) {
    return {
      supported: false,
      chain: requested,
      reason: `unsupported chain: ${requested}`
    };
  }

  return {
    supported: true,
    chain: requested,
    config: CHAIN_CONFIG[requested] || CHAIN_CONFIG.evm
  };
}

export async function discoverLiquidityPairs(chain, address) {
  const base = String(cfg.DEXSCREENER_API_BASE || "https://api.dexscreener.com/latest").replace(/\/+$/, "");
  const url = `${base}/dex/tokens/${address}`;
  console.log("[provider] liquidity lookup start", { chain, address, hasBase: Boolean(base) });

  try {
    const data = await fetchJson(url);
    const pairs = Array.isArray(data?.pairs) ? data.pairs : [];
    console.log("[provider] liquidity lookup success", { chain, address, pairCount: pairs.length });
    return pairs;
  } catch (err) {
    console.error("[provider] liquidity lookup failure", { chain, address, err: safeErr(err) });
    return [];
  }
}

export async function fetchOwnershipData(chain, address) {
  console.log("[provider] ownership lookup start", { chain, address });
  try {
    const rpcUrl = (CHAIN_CONFIG[chain] || CHAIN_CONFIG.evm || {}).rpcUrl || "";
    if (!rpcUrl) {
      return { owner: "", source: "none", verifiable: false, note: "No RPC URL configured." };
    }

    console.log("[provider] ownership lookup success", { chain, address, rpcConfigured: true });
    return { owner: "", source: "rpc", verifiable: false, note: "Ownership RPC probe not configured for contract ABI discovery yet." };
  } catch (err) {
    console.error("[provider] ownership lookup failure", { chain, address, err: safeErr(err) });
    return { owner: "", source: "error", verifiable: false, note: safeErr(err) };
  }
}

export async function fetchHolderData(chain, address) {
  console.log("[provider] holder lookup start", { chain, address });
  try {
    console.log("[provider] holder lookup success", { chain, address, available: false });
    return { available: false, holders: [], note: "Holder distribution source is not configured." };
  } catch (err) {
    console.error("[provider] holder lookup failure", { chain, address, err: safeErr(err) });
    return { available: false, holders: [], note: safeErr(err) };
  }
}

tokenScreener.js.content:
import { inferChain } from "./provider.js";
import { analyzeOwnership } from "./ownershipAnalyzer.js";
import { analyzeLiquidity } from "./liquidityAnalyzer.js";
import { analyzeHolders } from "./holderAnalyzer.js";
import { getCachedScan, saveCachedScan } from "./cacheStore.js";
import { saveHistory } from "./historyStore.js";
import { getBotProfile } from "../lib/botProfile.js";

function computeOverall({ ownership, liquidity, holders }) {
  const statuses = [ownership.status, liquidity.status, holders.status];
  if (statuses.includes("FAIL")) return "High Risk";
  if (statuses.includes("UNKNOWN")) return "Unknown";
  if (statuses.includes("WARN")) return "Caution";
  if (statuses.every((s) => s === "PASS")) return "Low Confidence Safe";
  return "Unknown";
}

export async function screenToken({ address, chainHint, userId, chatId, source }) {
  const chainInfo = inferChain(address, chainHint);
  if (!chainInfo.supported) {
    return {
      address,
      chain: chainInfo.chain,
      ownership: { status: "UNKNOWN" },
      liquidity: { status: "UNKNOWN" },
      holders: { status: "UNKNOWN" },
      overall: "Unknown",
      notes: [
        `Unsupported chain. Supported chains: ${chainInfo.chain === "unknown" ? "evm" : "evm"}.`,
        chainInfo.reason
      ],
      botProfile: getBotProfile()
    };
  }

  const cached = await getCachedScan({ chain: chainInfo.chain, address });
  if (cached) {
    await saveHistory({ userId, chatId, address, chain: chainInfo.chain, overall: cached.overall, source: `${source}:cache` });
    return {
      ...cached,
      notes: [...(cached.notes || []), "Returned from recent cache."]
    };
  }

  const [ownership, liquidity, holders] = await Promise.all([
    analyzeOwnership({ chain: chainInfo.chain, address }),
    analyzeLiquidity({ chain: chainInfo.chain, address }),
    analyzeHolders({ chain: chainInfo.chain, address })
  ]);

  const notes = [
    ...(ownership.notes || []),
    ...(liquidity.notes || []),
    ...(holders.notes || [])
  ];

  if (holders.status === "UNKNOWN") {
    notes.push("Unknown holder data does not produce a safe verdict.");
  }

  const result = {
    address,
    chain: chainInfo.chain,
    ownership,
    liquidity,
    holders,
    overall: computeOverall({ ownership, liquidity, holders }),
    notes,
    botProfile: getBotProfile()
  };

  await saveCachedScan({ chain: chainInfo.chain, address, result });
  await saveHistory({ userId, chatId, address, chain: chainInfo.chain, overall: result.overall, source });

  return result;
}

